  "fetched_sources": [
    {
      "title": "A Survey of LLM-based Deep Search Agents: Paradigm, Optimization, Evaluation, and Challenges",
      "url": "https://arxiv.org/html/2508.05668v2",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "First systematic survey of search agents. Analyzes architecture, optimization, application, evaluation. Categorizes works and identifies open challenges. Repository: github.com/YunjiaXi/Awesome-Search-Agent-Papers. Covers OpenAI Deep Research, Gemini, Perplexity as leading examples.",
      "notes": "arXiv preprint, 2025. Comprehensive survey, highly relevant."
    },
    {
      "title": "Fathom-DeepResearch: Unlocking Long Horizon Information Retrieval and Synthesis for SLMs",
      "url": "https://arxiv.org/pdf/2509.24107",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Agentic system with two 4B models: Fathom-Search-4B (DeepSearch) and Fathom-Synthesizer-4B. Introduces DUETQA dataset, RAPO (RL extension), steerable rewards. SOTA on SimpleQA, FRAMES, WebWalker, DeepResearch-Bench among open-weights models. Supports >20 tool calls.",
      "notes": "arXiv preprint 2025. Strong empirical results with small models."
    },
    {
      "title": "InfoAgent: Advancing Autonomous Information-Seeking Agents",
      "url": "https://arxiv.org/html/2509.25189v1",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Deep research agent from Qwen3-14B. Novel data pipeline using entity tree sub-tree sampling with entity fuzzification. Self-hosted search infrastructure. Two-stage training: SFT cold-start + RL. Achieves 15.3% on BrowseComp, 29.2% on BrowseComp-ZH, 40.4% on Xbench-DS. Outperforms WebSailor-72B and DeepDive-32B.",
      "notes": "arXiv preprint 2025. Submitted to ICLR 2026. Key contribution in data synthesis."
    },
    {
      "title": "WebThinker: Empowering Large Reasoning Models with Deep Research Capability",
      "url": "https://arxiv.org/pdf/2504.21776",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Deep research agent for LRMs. Deep Web Explorer module for dynamic search/navigation. Autonomous Think-Search-and-Draft strategy. RL via iterative online DPO. Outperforms on GPQA, GAIA, WebWalkerQA, HLE, Glaive. Code: github.com/RUC-NLPIR/WebThinker.",
      "notes": "arXiv preprint 2025. Integrates reasoning, search, and report writing."
    },
    {
      "title": "Deep Research Agents: A Systematic Examination And Roadmap",
      "url": "https://arxiv.org/pdf/2506.18096",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Detailed analysis of DRA foundational technologies. Compares API-based retrieval vs browser-based exploration. Reviews modular tool-use, MCPs, single/multi-agent configurations. Provides benchmark comparison table across HotpotQA, NQ, TQ, GPQA etc. Identifies limitations in current benchmarks.",
      "notes": "arXiv preprint 2025. Comprehensive roadmap with extensive benchmark table."
    },
    {
      "title": "FlowSearch: Advancing deep research with dynamic structured knowledge flow",
      "url": "https://arxiv.org/html/2510.08521v1",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Multi-agent framework with dynamic knowledge flow for parallel exploration and hierarchical decomposition. SOTA on GAIA, HLE, GPQA, TRQA. Code: github.com/Alpha-Innovator/InternAgent. Demonstrates 7-node execution graph for multi-agent AI scientists query.",
      "notes": "arXiv preprint 2025. Novel knowledge flow structure."
    },
    {
      "title": "WebResearcher: Unleashing unbounded reasoning capability in Long-Horizon Agents",
      "url": "https://arxiv.org/pdf/2509.13309",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "IterResearch paradigm reformulating deep research as MDP with periodic consolidation. WebFrontier data synthesis engine. Parallel multi-agent exploration. SOTA across 6 benchmarks, surpassing proprietary systems. Uses Qwen3-30B-A3B backbone.",
      "notes": "arXiv preprint 2025. Addresses context suffocation in mono-contextual approaches."
    },
    {
      "title": "ManuSearch: Democratizing Deep Search in Large Language Models with a Transparent and Open Multi-Agent Framework",
      "url": "https://aclanthology.org/2025.findings-emnlp.130.pdf",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Three-agent framework: solution planning, internet search, webpage reading agents. Introduces ORION benchmark for open-web reasoning over long-tail entities (English + Chinese). Outperforms prior open-source baselines and surpasses some closed-source systems. Code: github.com/RUCAIBox/ManuSearch.",
      "notes": "EMNLP 2025 Findings. Modular, interpretable framework."
    },
    {
      "title": "INFOGENT: An Agent-Based Framework for Web Information Aggregation",
      "url": "https://aclanthology.org/2025.findings-naacl.318.pdf",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Framework with Navigator, Extractor, Aggregator components. Considers Direct API-driven Access and Interactive Visual Access. Beats SOTA multi-agent search by 7% on FRAMES and improves by 4.3% on AssistantBench.",
      "notes": "NAACL 2025 Findings. Focuses on information aggregation tasks."
    },
    {
      "title": "WebDancer: Towards Autonomous Information Seeking Agency",
      "url": "https://arxiv.org/html/2505.22648",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Four-stage pipeline: browsing data construction, trajectory sampling, SFT cold start, RL for generalization. Based on ReAct. Strong results on GAIA and WebWalkerQA. Systematic framework for building information-seeking web agents.",
      "notes": "arXiv preprint 2025. End-to-end pipeline perspective."
    },
    {
      "title": "BrowseMaster: A scalable framework for reasoning-intensive web browsing",
      "url": "https://arxiv.org/pdf/2508.09129",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Planner-executor agent pair. Programmatic search strategies. First open-source agent to exceed 30% on BrowseComp-en (score 30.0). Surpasses OpenAI DeepResearch by 4% on BrowseComp-zh (46.5). Code-based search strategies for long-horizon tasks.",
      "notes": "arXiv preprint 2025. Strong results on BrowseComp."
    },
    {
      "title": "Lucy: edgerunning agentic web search on mobile with machine generated task vectors",
      "url": "https://arxiv.org/pdf/2508.00360",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "1.7B parameter SLM achieving 78.3% on SimpleQA via RLVR and MCP integration. Task vector machine paradigm. Matches DeepSeek-V3 performance. Demonstrates small models can rival large ones for agentic search.",
      "notes": "arXiv preprint 2025. Novel perspective on dynamic reasoning in small models."
    },
    {
      "title": "EvolveSearch: An Iterative Self-Evolving Search Agent",
      "url": "https://aclanthology.org/2025.emnlp-main.663.pdf",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Iterative self-evolution framework alternating RL exploration and SFT optimization. No human-annotated reasoning data needed. Average 4.7% improvement over prior SOTA across 7 multi-hop QA benchmarks. Addresses data scarcity and RL convergence issues.",
      "notes": "EMNLP 2025 Main. First to iteratively combine RL and SFT for web search."
    },
    {
      "title": "ReSearch: Learning to Reason with Search for LLMs via Reinforcement Learning",
      "url": "https://arxiv.org/pdf/2503.19470",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Framework training LLMs to reason with search via GRPO without supervised reasoning steps. Search operations integral to reasoning chain. Trained on Qwen2.5-7B/32B. Improvements of 8.9%-22.4% over baselines. Naturally elicits reflection and self-correction.",
      "notes": "arXiv preprint 2025. Treats search as part of chain-like reasoning."
    },
    {
      "title": "R-Search: Empowering LLM Reasoning with Search via Multi-Reward Reinforcement Learning",
      "url": "https://arxiv.org/pdf/2506.04185",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Multi-stage, multi-type reward mechanism for reasoning-search trajectories. Outperforms advanced RAG baselines by up to 32.2% in-domain and 25.1% out-of-domain. Includes R-Search-as-a-Tool for modularized search.",
      "notes": "arXiv preprint 2025. Focuses on reward design for search-reasoning integration."
    },
    {
      "title": "SE-Agent: Self-Evolution Trajectory Optimization in Multi-Step Reasoning with LLM-Based Agents",
      "url": "https://arxiv.org/pdf/2508.02085",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Self-evolution framework using revision, recombination, refinement of trajectories. Up to 55% relative improvement on SWE-bench Verified. SOTA among open-source agents (61.2% with Claude-3.7-Sonnet, 80.0% with Claude-4-Sonnet).",
      "notes": "arXiv preprint 2025. Focus on software engineering tasks but generalizable."
    },
    {
      "title": "STEPSEARCH: Igniting LLMs Search Ability via Step-Wise Proximal Policy Optimization",
      "url": "https://aclanthology.org/2025.emnlp-main.1106v1.pdf",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Step-wise PPO with intermediate search rewards based on information gain and redundancy penalties. 11.2% and 4.2% absolute improvements for 3B and 7B models over global-reward baselines using only 19k training data. Sub-question-level search trajectories.",
      "notes": "EMNLP 2025 Main. Fine-grained stepwise supervision for search agents."
    },
    {
      "title": "Search-o1: Agentic Search-Enhanced Large Reasoning Models",
      "url": "https://aclanthology.org/anthology-files/anthology-files/pdf/emnlp/2025.emnlp-main.276.pdf",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Enhances LRMs with agentic RAG and Reason-in-Documents module for refining retrieved documents. Dynamic retrieval when LRMs encounter knowledge gaps. Strong performance on science, math, coding, and 6 open-domain QA benchmarks. Code: github.com/RUC-NLPIR/Search-o1.",
      "notes": "EMNLP 2025 Main. Integrates search into LRM reasoning process."
    },
    {
      "title": "DeepResearch Bench: A Comprehensive Benchmark for Deep Research Agents",
      "url": "https://github.com/Ayanami0730/deep_research_bench",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "100 PhD-level research tasks across 22 fields. Two evaluation frameworks: RACE (reference-based quality) and FACT (citation accuracy). Real-world query distribution from 96,147 anonymized user queries. Leaderboard on Hugging Face. Apache 2.0 license.",
      "notes": "GitHub repository with arXiv paper (2506.11763). Active benchmark with multiple evaluations."
    },
    {
      "title": "How Far Are We from Genuinely Useful Deep Research Agents?",
      "url": "https://arxiv.org/pdf/2512.01948",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Introduces Finder benchmark (100 tasks, 419 checklist items) and DEFT failure taxonomy (14 failure modes across reasoning, retrieval, generation). Analyzes ~1000 reports. Finds DRAs struggle with evidence integration, verification, and reasoning-resilient planning, not task comprehension.",
      "notes": "arXiv preprint 2025. First failure taxonomy for DRAs."
    },
    {
      "title": "Step-DeepResearch Technical Report",
      "url": "https://arxiv.org/pdf/2512.20491",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Cost-effective 32B DRA. Atomic Capability Data Synthesis, progressive training (mid-training→SFT→RL), Checklist-style Judger reward. ADR-Bench Chinese benchmark. 61.42 on Scale AI ResearchRubrics, rivaling OpenAI and Gemini DeepResearch. Most cost-effective DRA.",
      "notes": "arXiv preprint 2025. Focus on cost efficiency with medium-sized models."
    },
    {
      "title": "DeepResearcher: Scaling Deep Research via Reinforcement Learning in Real-world Environments",
      "url": "https://aclanthology.org/2025.emnlp-main.22.pdf",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "First framework for end-to-end RL training of DRAs in real web environments. Multi-agent architecture for browsing. Up to 28.9 points improvement over prompt engineering, 7.2 over RAG-based RL. Emergent behaviors: planning, cross-validation, self-reflection, honesty. Code: github.com/GAIR-NLP/DeepResearcher.",
      "notes": "EMNLP 2025 Main. Real-world web training emphasis."
    },
    {
      "title": "DeepResearch-9K: A Challenging Benchmark Dataset of Deep-Research Agent",
      "url": "https://arxiv.org/html/2603.01152",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "9000 questions across 3 difficulty levels (L1-L3). High-quality search trajectories from Tongyi-DeepResearch-30B-A3B. DeepResearch-R1 training framework supporting multi-turn web interactions, various RL approaches, and different reward models. L3 accuracy only 23.73% for teacher model.",
      "notes": "arXiv preprint 2026. Large-scale challenging benchmark with training framework."
    },
    {
      "title": "Rethinking the Design of Reinforcement Learning-Based Deep Research Agents",
      "url": "https://arxiv.org/html/2510.15862v4",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Formalizes deep research as RL in episodic MDP. Identifies 4 key factors: AI feedback rewards (vs rule-based), on-policy RLOO (vs off-policy GRPO), filtering low-quality samples, error-tolerant test-time rollout. SOTA among 7B-scale agents across 10 benchmarks.",
      "notes": "arXiv preprint 2025. Systematic ablation study of design choices."
    },
    {
      "title": "PaSa: An LLM Agent for Comprehensive Academic Paper Search",
      "url": "https://aclanthology.org/2025.acl-long.572.pdf",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Two-agent system: Crawler and Selector. AutoScholarQuery dataset (35k queries). RealScholarQuery benchmark. PaSa-7B surpasses Google+GPT-4o by 37.78% recall@20 and 39.90% recall@50. RL optimization via AGILE framework. Code: github.com/bytedance/pasa.",
      "notes": "ACL 2025 Long. Specialized for academic paper search."
    },
    {
      "title": "DynaSearcher: Dynamic Knowledge Graph Augmented Search Agent via Multi-Reward Reinforcement Learning",
      "url": "https://arxiv.org/html/2507.17365v2",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Knowledge graphs as structured external knowledge guiding search via entity relationships. Multi-reward RL for retrieval accuracy, efficiency, and response quality. SOTA on 6 multi-hop QA datasets. Strong generalization across retrieval environments and larger models.",
      "notes": "arXiv preprint 2025. Unique KG-augmented approach."
    }
  ]
}
